## CVXPY SOURCE: reductions/eliminate_pwl/canonicalizers/minimum_canon.py
## min(x1, x2, ...) = -max(-x1, -x2, ...)


minimum_canon <- function(expr, args, solver_context = NULL) {
  neg_args <- lapply(args, function(xi) -xi)
  ## Create a Maximum atom from negated args to get proper shapes
  tmp <- do.call(Maximum, neg_args)
  result <- maximum_canon(tmp, tmp@args)
  list(-result[[1L]], result[[2L]])
}

method(dcp_canonicalize, Minimum) <- minimum_canon
method(has_dcp_canon, Minimum) <- function(expr) TRUE
